    "    border:1px solid #2a3d52;border-radius:4px;padding:9px 20px;flex:0}"
    "  a.back:hover{color:#ddeeff}"
    "  .warn{color:#ffcc00;font-size:.78rem;margin-top:16px;line-height:1.6}"
    "</style></head><body>"
    "<h2>WiFi Settings</h2>"
    "<p>New credentials are saved to flash and survive firmware updates.</p>"
    "<div class='current'>"
    "  Current SSID: <span id='cur'>loading...</span>"
    "</div>"
    "<form method='POST' action='/wifi'>"
    "  <label>NEW SSID</label>"
    "  <input type='text' name='ssid' placeholder='Network name' autocomplete='off' required>"
    "  <label>NEW PASSWORD</label>"
    "  <input type='password' name='pass' placeholder='Leave empty for open network'>"
    "  <div class='btn-row'>"
    "    <a class='back' href='/'>&#8592; Back</a>"
    "    <input type='submit' value='Save &amp; Reboot'>"
    "  </div>"
    "</form>"
    "<div class='warn'>"
    "&#9888; After saving, the board reboots and connects to the new network.<br>"
    "If connection fails, it restarts in AP mode at 192.168.4.1"
    "</div>"
    "<script>"
    "fetch('/api/state').then(r=>r.json()).then(d=>{"
    "  document.getElementById('cur').textContent = d.ip ? d.ssid||'connected ('+d.ip+')' : 'not connected';"
    "}).catch(()=>{ document.getElementById('cur').textContent='unknown'; });"
    "</script>"
    "</body></html>";

